--- .storybook/eval-support/transcript.tsx
import { useEffect, useRef, useState } from 'react';
import type {
	AssistantMessage,
	TranscriptMessage,
	TranscriptProps,
	ResultMessage,
	SystemMessage,
	TextContent,
	ToolResultContent,
	ToolUseContent,
	UserMessage,
} from './transcript.types.ts';

const formatJsonWithPreservedWhitespace = (obj: any): string => {
	return JSON.stringify(obj, null, 2)
		.replace(/\\\\n/g, '\\n')
		.replace(/\\n/g, '\n')
		.replace(/\\\\t/g, '\\t')
		.replace(/\\t/g, '\t');
};

const truncateText = (text: string, maxLength: number): string => {
	return text.length <= maxLength ? text : text.substring(0, maxLength) + '...';
};

const getPercentageStyle = (percentage: number): React.CSSProperties => {
	const adjustedPercentage = Math.max(0, percentage - 5);
	const intensity = Math.min(adjustedPercentage / 25, 1);
	const red = Math.round(245 + (248 - 245) * intensity);
	const green = Math.round(245 * (1 - intensity));
	const blue = Math.round(245 * (1 - intensity));
	const bgColor = `rgb(${red}, ${green}, ${blue})`;
	const textColor = intensity > 0.4 ? '#ffffff' : '#666';
	return { background: bgColor, color: textColor };
};

const MetadataCard = ({
	title,
	value,
	subvalue,
	html,
}: {
	title: string;
	value?: string | number;
	subvalue?: string;
	html?: string;
}) => (
	<div
		style={{
			padding: '1.5rem',
			backgroundColor: '#f9fafb',
			border: '1px solid #e5e7eb',
			borderRadius: '8px',
		}}
	>
		<h3
			style={{
				margin: '0 0 0.5rem 0',
				fontSize: '0.875rem',
				fontWeight: 600,
				color: '#6b7280',
				textTransform: 'uppercase',
				letterSpacing: '0.05em',
			}}
		>
			{title}
		</h3>
		{html ? (
			<div dangerouslySetInnerHTML={{ __html: html }} />
		) : (
			<>
				<div style={{ fontSize: '1.5rem', fontWeight: 700, color: '#111827' }}>{value}</div>
				{subvalue && (
					<div
						style={{
							fontSize: '0.875rem',
							color: '#6b7280',
							marginTop: '0.25rem',
						}}
					>
						{subvalue}
					</div>
				)}
			</>
		)}
	</div>
);

const CodeBlock = ({
	content,
	language = '',
	isError = false,
}: {
	content: string;
	language?: string;
	isError?: boolean;
}) => {
	const [isTruncated, setIsTruncated] = useState(content.length > 500);
	const codeRef = useRef<HTMLElement>(null);

	useEffect(() => {
		if (codeRef.current && (globalThis as any).hljs) {
			(globalThis as any).hljs.highlightElement(codeRef.current);
		}
	}, [content, isTruncated]);

	return (
		<div style={{ position: 'relative', marginBottom: '1rem' }}>
			<pre
				style={{
					margin: 0,
					padding: '1rem',
					backgroundColor: isError ? '#fef2f2' : '#1e1e1e',
					color: isError ? '#991b1b' : '#d4d4d4',
					borderRadius: '6px',
					overflow: isTruncated ? 'hidden' : 'auto',
					fontSize: '0.875rem',
					fontFamily: 'monospace',
					border: isError ? '1px solid #fecaca' : 'none',
					maxHeight: isTruncated ? '300px' : 'none',
					position: 'relative',
					whiteSpace: 'pre-wrap',
					wordBreak: 'break-word',
				}}
			>
				<code ref={codeRef} className={language ? `language-${language}` : ''}>
					{content}
				</code>
				{isTruncated && content.length > 500 && (
					<div
						style={{
							position: 'absolute',
							bottom: 0,
							left: 0,
							right: 0,
							height: '60px',
							background: isError
								? 'linear-gradient(transparent, #fef2f2)'
								: 'linear-gradient(transparent, #1e1e1e)',
							pointerEvents: 'none',
						}}
					/>
				)}
			</pre>
			{content.length > 500 && (
				<button
					onClick={() => setIsTruncated(!isTruncated)}
					style={{
						marginTop: '0.5rem',
						padding: '0.5rem 1rem',
						backgroundColor: '#3b82f6',
						color: 'white',
						border: 'none',
						borderRadius: '4px',
						cursor: 'pointer',
						fontSize: '0.875rem',
					}}
				>
					{isTruncated ? 'Show more' : 'Show less'}
				</button>
			)}
		</div>
	);
};

const ContentSection = ({ label, children }: { label: string; children: React.ReactNode }) => (
	<div style={{ marginBottom: '1rem' }}>
		<div
			style={{
				fontSize: '0.75rem',
				fontWeight: 600,
				color: '#6b7280',
				textTransform: 'uppercase',
				letterSpacing: '0.05em',
				marginBottom: '0.5rem',
			}}
		>
			{label}
		</div>
		{children}
	</div>
);

const FileContent = ({
	filePath,
	content,
	language = 'typescript',
}: {
	filePath: string;
	content: string;
	language?: string;
}) => (
	<>
		<ContentSection label="File Path">
			<code
				style={{
					background: '#f9f9f9',
					padding: '0.25rem 0.5rem',
					borderRadius: '4px',
					fontSize: '0.875rem',
					fontFamily: 'monospace',
				}}
			>
				{filePath}
			</code>
		</ContentSection>
		<ContentSection label="Content">
			<CodeBlock content={content} language={language} />
		</ContentSection>
	</>
);

